from pathlib import Path
import json


def build_course_plan(root):
    root = Path(root)
    root.mkdir(exist_ok=True)

    structure = {
        'Programming Concepts': ['notes', 'labs', 'assignments'],
        'Networking Basics': ['notes', 'labs', 'packet-tracer'],
        'Operating Systems': ['notes', 'scripts', 'reports'],
    }

    plan = {}
    for course, folders in structure.items():
        course_dir = root / course.lower().replace(' ', '-')
        course_dir.mkdir(exist_ok=True)
        for folder in folders:
            (course_dir / folder).mkdir(exist_ok=True)
        plan[course] = [str((course_dir / folder).relative_to(root)) for folder in folders]

    (root / 'plan.json').write_text(json.dumps(plan, indent=2), encoding='utf-8')
    return plan


if __name__ == '__main__':
    plan = build_course_plan('semester-plan')
    print('Created folders for', len(plan), 'courses.')

