import struct


def decode_frame(frame):
    header = struct.unpack('!HHB', frame[:7])
    return {
        'source': header[0],
        'destination': header[1],
        'type': header[2],
        'payload': frame[7:].decode('utf-8', errors='ignore'),
    }


if __name__ == '__main__':
    sample = b'\x00\x01\x00\x02\x03hello'
    print(decode_frame(sample))

from ipaddress import ip_network, ip_address


def best_route(destination, routes):
    dest = ip_address(destination)
    best = None
    best_prefix = -1

    for network, gateway in routes:
        net = ip_network(network)
        if dest in net:
            prefix = net.prefixlen
            if prefix > best_prefix:
                best = gateway
                best_prefix = prefix

    return best


if __name__ == '__main__':
    routes = [('10.0.0.0/8', '192.168.1.254'), ('10.1.0.0/16', '192.168.2.1')]
    print(best_route('10.1.5.8', routes))

import sqlite3


class InventoryDB:
    def __init__(self, db_name='inventory.db'):
        self.conn = sqlite3.connect(db_name)
        self.conn.execute('''
            CREATE TABLE IF NOT EXISTS devices (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                ip TEXT UNIQUE NOT NULL,
                type TEXT NOT NULL
            )
        ''')
        self.conn.commit()

    def add_device(self, name, ip, device_type):
        self.conn.execute(
            'INSERT INTO devices (name, ip, type) VALUES (?, ?, ?)',
            (name, ip, device_type),
        )
        self.conn.commit()

    def list_devices(self):
        return self.conn.execute('SELECT id, name, ip, type FROM devices ORDER BY name').fetchall()


if __name__ == '__main__':
    db = InventoryDB()
    db.add_device('Core-SW1', '10.0.0.1', 'Switch')
    print(db.list_devices())

