def classify_message(text):
    lowered = text.lower()
    spam_keywords = ['buy', 'win', 'click', 'offer', 'free']
    score = sum(1 for keyword in spam_keywords if keyword in lowered)
    return 'spam' if score >= 2 else 'safe'


