import socket


def diagnose(host):
    results = {'dns': None, 'tcp': None}
    try:
        results['dns'] = socket.gethostbyname(host)
    except socket.gaierror:
        results['dns'] = 'UNRESOLVED'

    try:
        with socket.create_connection((host, 80), timeout=2):
            results['tcp'] = 'OPEN'
    except OSError:
        results['tcp'] = 'CLOSED'

    return results


if __name__ == '__main__':
    print(diagnose('example.com'))

