import re


def password_strength(password):
    if len(password) >= 12 and re.search(r'\d', password) and re.search(r'[A-Z]', password):
        return 'strong'
    return 'weak'


def flag_suspicious(logs):
    suspicious = []
    for entry in logs:
        if 'FAIL' in entry.upper() and '3' in entry:
            suspicious.append(entry)
    return suspicious


if __name__ == '__main__':
    print(password_strength('SecurePass2026'))
    print(flag_suspicious(['FAIL login 1', 'FAIL login 2', 'OK login 1']))

