import socket


def scan_ports(host, ports):
    found = []
    for port in ports:
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as sock:
            sock.settimeout(0.2)
            try:
                sock.connect((host, port))
                found.append(port)
            except OSError:
                pass
    return found


if __name__ == '__main__':
    print(scan_ports('localhost', [22, 80, 443]))

from math import sqrt


def classify(point, examples, k=3):
    distances = []
    for values, label in examples:
        dist = sqrt(sum((a - b) ** 2 for a, b in zip(point, values)))
        distances.append((dist, label))

    distances.sort(key=lambda item: item[0])
    votes = [label for _, label in distances[:k]]
    return max(set(votes), key=votes.count)


if __name__ == '__main__':
    examples = [([1, 1], 'A'), ([2, 2], 'B'), ([3, 3], 'B')]
    print(classify([1.2, 1.1], examples))

